select count(*) from postgres.comments as c, postgres.posthistory as ph, postgres.badges as b, postgres.users as u where u.id = b.userid and u.id = ph.userid and u.id = c.userid and ph.posthistorytypeid=2 and ph.creationdate<=timestamp '2014-08-01 13:56:22' and b."date"<=timestamp '2014-09-02 23:33:16' and u.views>=0 and u.downvotes>=0 and u.upvotes>=0 and u.upvotes<=62 and u.creationdate>=timestamp '2010-07-27 17:10:30' and u.creationdate<=timestamp '2014-07-31 18:48:36';
